protected <S extends T> TypedQuery<Long> getCountQuery(Specification<S> spec, Class<S> domainClass) {

	Assert.notNull(spec, "Specification must not be null");

	CriteriaBuilder builder = entityManager.getCriteriaBuilder();
	CriteriaQuery<Long> query = builder.createQuery(Long.class);

	Root<S> root = applySpecificationToCriteria(spec, domainClass, query);

	if (query.isDistinct()) {
		query.select(builder.countDistinct(root));
	} else {
		query.select(builder.count(root));
	}

	// Remove all Orders the Specifications might have applied
	query.orderBy(Collections.emptyList());

	return applyRepositoryMethodMetadataForCount(entityManager.createQuery(query));
}

public HttpHeaders prepareHeaders(PersistentEntity<?, ?> entity, Object value) {

	Assert.notNull(entity, "PersistentEntity must not be null");
	Assert.notNull(value, "Entity value must not be null");
	Assert.isInstanceOf(entity.getType(), value, () ->
		String.format("Target bean of type %s is not of type of the persistent entity (%s)", value.getClass().getName(), entity.getType().getName()));

	// Add ETag
	HttpHeaders headers = ETag.from(entity, value).addTo(new HttpHeaders());

	// Add Last-Modified
	getLastModifiedInMilliseconds(value).ifPresent(it -> headers.setLastModified(it));

	return headers;
}

public SearchResourceMappings(List<MethodResourceMapping> mappings) {

	Assert.notNull(mappings, "MethodResourceMappings must not be null");

	this.mappings = new HashMap<Path, MethodResourceMapping>(mappings.size());

	for (MethodResourceMapping mapping : mappings) {

		MethodResourceMapping existing = this.mappings.get(mapping.getPath());

		if (existing != null) {
			throw new IllegalStateException(
					String.format(AMBIGUOUS_MAPPING, existing.getMethod(), mapping.getMethod(), existing.getPath()));
		}

		this.mappings.put(mapping.getPath(), mapping);
	}
}

@Override
	public ExitStatus run(String... args) throws Exception {
		try {
			int index = (args.length != 0) ? Integer.parseInt(args[0]) - 1 : 0;
			List<String> arguments = new ArrayList<>(args.length);
			for (int i = 2; i < args.length; i++) {
				arguments.add(args[i]);
			}
			String starting = "";
			if (index < arguments.size()) {
				starting = arguments.remove(index);
			}
			if (index == 0) {
				showCommandHints(starting);
			}
			else if (!arguments.isEmpty() && !starting.isEmpty()) {
				String command = arguments.remove(0);
				showCommandOptionHints(command, Collections.unmodifiableList(arguments), starting);
			}
		}
		catch (Exception ex) {
			// Swallow and provide no hints
			return ExitStatus.ERROR;
		}
		return ExitStatus.OK;
	}

protected List<String> getExcludeAutoConfigurationsProperty() {
	Environment environment = getEnvironment();
	if (environment == null) {
		return Collections.emptyList();
	}
	if (environment instanceof ConfigurableEnvironment) {
		Binder binder = Binder.get(environment);
		return binder.bind(PROPERTY_NAME_AUTOCONFIGURE_EXCLUDE, String[].class)
			.map(Arrays::asList)
			.orElse(Collections.emptyList());
	}
	String[] excludes = environment.getProperty(PROPERTY_NAME_AUTOCONFIGURE_EXCLUDE, String[].class);
	return (excludes != null) ? Arrays.asList(excludes) : Collections.emptyList();
}

private int getOrder() {
	if (wasProcessed()) {
		Assert.state(this.autoConfigurationMetadata != null, "'autoConfigurationMetadata' must not be null");
		return this.autoConfigurationMetadata.getInteger(this.className, "AutoConfigureOrder",
				AutoConfigureOrder.DEFAULT_ORDER);
	}
	Map<String, @Nullable Object> attributes = getAnnotationMetadata()
		.getAnnotationAttributes(AutoConfigureOrder.class.getName());
	if (attributes != null) {
		Integer value = (Integer) attributes.get("value");
		Assert.state(value != null, "'value' must not be null");
		return value;
	}
	return AutoConfigureOrder.DEFAULT_ORDER;
}

ConditionOutcome getUltimateOutcome() {
	ConditionMessage.Builder message = ConditionMessage
		.forCondition("NestedCondition on " + ClassUtils.getShortName(this.metadata.getClassName()));
	if (this.outcomes.size() == 1) {
		ConditionOutcome outcome = this.outcomes.get(0);
		return new ConditionOutcome(outcome.isMatch(), message.because(outcome.getMessage()));
	}
	List<ConditionOutcome> match = new ArrayList<>();
	List<ConditionOutcome> nonMatch = new ArrayList<>();
	for (ConditionOutcome outcome : this.outcomes) {
		(outcome.isMatch() ? match : nonMatch).add(outcome);
	}
	if (nonMatch.isEmpty()) {
		return ConditionOutcome.match(message.found("matching nested conditions").items(match));
	}
	return ConditionOutcome.noMatch(message.found("non-matching nested conditions").items(nonMatch));
}

private ConditionOutcome getMatchOutcome(String[] locations) {
	if (!isJndiAvailable()) {
		return ConditionOutcome
			.noMatch(ConditionMessage.forCondition(ConditionalOnJndi.class).notAvailable("JNDI environment"));
	}
	if (locations.length == 0) {
		return ConditionOutcome
			.match(ConditionMessage.forCondition(ConditionalOnJndi.class).available("JNDI environment"));
	}
	JndiLocator locator = getJndiLocator(locations);
	String location = locator.lookupFirstLocation();
	String details = "(" + StringUtils.arrayToCommaDelimitedString(locations) + ")";
	if (location != null) {
		return ConditionOutcome.match(ConditionMessage.forCondition(ConditionalOnJndi.class, details)
			.foundExactly("\"" + location + "\""));
	}
	return ConditionOutcome.noMatch(ConditionMessage.forCondition(ConditionalOnJndi.class, details)
		.didNotFind("any matching JNDI location")
		.atAll());
}

protected ConditionOutcome getResourceOutcome(ConditionContext context, AnnotatedTypeMetadata metadata) {
	List<String> found = new ArrayList<>();
	for (String location : this.resourceLocations) {
		Resource resource = context.getResourceLoader().getResource(location);
		if (resource != null && resource.exists()) {
			found.add(location);
		}
	}
	if (found.isEmpty()) {
		ConditionMessage message = startConditionMessage().didNotFind("resource", "resources")
			.items(Style.QUOTE, Arrays.asList(this.resourceLocations));
		return ConditionOutcome.noMatch(message);
	}
	ConditionMessage message = startConditionMessage().found("resource", "resources").items(Style.QUOTE, found);
	return ConditionOutcome.match(message);
}

public void aggregate(StepExecution result, Collection<StepExecution> executions) {
	Assert.notNull(result, "To aggregate into a result it must be non-null.");
	if (executions == null) {
		return;
	}
	Set<Long> stepExecutionIds = executions.stream().map(stepExecution -> {
		long id = stepExecution.getId();
		return id;
	}).collect(Collectors.toSet());
	JobExecution jobExecution = jobRepository.getJobExecution(result.getJobExecutionId());
	Assert.state(jobExecution != null,
			"Could not load JobExecution from JobRepository for id " + result.getJobExecutionId());
	List<StepExecution> updates = jobExecution.getStepExecutions()
		.stream()
		.filter(stepExecution -> stepExecutionIds.contains(stepExecution.getId()))
		.collect(Collectors.toList());
	delegate.aggregate(result, updates);
}

public void verifySupportedMethod(HttpMethod httpMethod, ResourceType resourceType)
			throws HttpRequestMethodNotSupportedException, ResourceNotFoundException {

		Assert.notNull(httpMethod, "HTTP method must not be null");
		Assert.notNull(resourceType, "EntityRepresentationModel type must not be null");

		if (!getResourceMetadata().isExported()) {
			throw new ResourceNotFoundException();
		}

		SupportedHttpMethods httpMethods = getResourceMetadata().getSupportedHttpMethods();
		HttpMethods supportedMethods = httpMethods.getMethodsFor(resourceType);

		if (!supportedMethods.contains(httpMethod)) {
			reject(httpMethod, supportedMethods);
		}
	}

public void verifySupportedMethod(HttpMethod httpMethod, PersistentProperty<?> property)
			throws HttpRequestMethodNotSupportedException {

		Assert.notNull(httpMethod, "HTTP method must not be null");
		Assert.notNull(property, "EntityRepresentationModel type must not be null");

		if (!getResourceMetadata().isExported()) {
			throw new ResourceNotFoundException();
		}

		SupportedHttpMethods httpMethods = getResourceMetadata().getSupportedHttpMethods();
		HttpMethods supportedMethods = httpMethods.getMethodsFor(property);

		if (!supportedMethods.contains(httpMethod)) {
			reject(httpMethod, supportedMethods);
		}
	}

List<String> get() {
	if (!this.loggedBasePackageInfo) {
		if (this.packages.isEmpty()) {
			if (logger.isWarnEnabled()) {
				logger.warn("@EnableAutoConfiguration was declared on a class "
						+ "in the default package. Automatic @Repository and "
						+ "@Entity scanning is not enabled.");
			}
		}
		else {
			if (logger.isDebugEnabled()) {
				String packageNames = StringUtils.collectionToCommaDelimitedString(this.packages);
				logger.debug("@EnableAutoConfiguration was declared on a class in the package '" + packageNames
						+ "'. Automatic @Repository and @Entity scanning is enabled.");
			}
		}
		this.loggedBasePackageInfo = true;
	}
	return this.packages;
}

private Map<AnnotationMetadata, List<Condition>> getMemberConditions(String[] members, ConfigurationPhase phase,
				String className) {
			MultiValueMap<AnnotationMetadata, Condition> memberConditions = new LinkedMultiValueMap<>();
			for (String member : members) {
				AnnotationMetadata metadata = getMetadata(member);
				for (String[] conditionClasses : getConditionClasses(metadata)) {
					for (String conditionClass : conditionClasses) {
						Condition condition = getCondition(conditionClass);
						validateMemberCondition(condition, phase, className);
						memberConditions.add(metadata, condition);
					}
				}
			}
			return Collections.unmodifiableMap(memberConditions);
		}

public ConditionMessage items(Style style, @Nullable Collection<?> items) {
	Assert.notNull(style, "'style' must not be null");
	StringBuilder message = new StringBuilder(this.reason);
	items = style.applyTo(items);
	if ((this.condition == null || items == null || items.size() <= 1)
			&& StringUtils.hasLength(this.singular)) {
		message.append(" ").append(this.singular);
	}
	else if (StringUtils.hasLength(this.plural)) {
		message.append(" ").append(this.plural);
	}
	if (!CollectionUtils.isEmpty(items)) {
		message.append(" ").append(StringUtils.collectionToDelimitedString(items, ", "));
	}
	return this.condition.because(message.toString());
}

@Override
	protected final @Nullable ConditionOutcome[] getOutcomes(@Nullable String[] autoConfigurationClasses,
			AutoConfigurationMetadata autoConfigurationMetadata) {
		@Nullable ConditionOutcome[] outcomes = new ConditionOutcome[autoConfigurationClasses.length];
		for (int i = 0; i < outcomes.length; i++) {
			String autoConfigurationClass = autoConfigurationClasses[i];
			if (autoConfigurationClass != null) {
				Set<String> onBeanTypes = autoConfigurationMetadata.getSet(autoConfigurationClass, "ConditionalOnBean");
				outcomes[i] = getOutcome(onBeanTypes, ConditionalOnBean.class);
				if (outcomes[i] == null) {
					Set<String> onSingleCandidateTypes = autoConfigurationMetadata.getSet(autoConfigurationClass,
							"ConditionalOnSingleCandidate");
					outcomes[i] = getOutcome(onSingleCandidateTypes, ConditionalOnSingleCandidate.class);
				}
			}
		}
		return outcomes;
	}

private boolean isCandidate(ConfigurableListableBeanFactory beanFactory, String name,
			@Nullable BeanDefinition definition, Set<String> ignoredBeans) {
		if (ignoredBeans.contains(name)) {
			return false;
		}
		if (definition == null || (definition.isAutowireCandidate() && isDefaultCandidate(definition))) {
			return true;
		}
		if (ScopedProxyUtils.isScopedTarget(name)) {
			try {
				BeanDefinition originalDefinition = beanFactory
					.getBeanDefinition(ScopedProxyUtils.getOriginalBeanName(name));
				if (originalDefinition.isAutowireCandidate() && isDefaultCandidate(originalDefinition)) {
					return true;
				}
			}
			catch (NoSuchBeanDefinitionException ex) {
			}
		}
		return false;
	}

private Set<String> extract(@Nullable MultiValueMap<String, @Nullable Object> attributes,
				String... attributeNames) {
			if (CollectionUtils.isEmpty(attributes)) {
				return Collections.emptySet();
			}
			Set<String> result = new LinkedHashSet<>();
			for (String attributeName : attributeNames) {
				List<@Nullable Object> values = attributes.getOrDefault(attributeName, Collections.emptyList());
				for (Object value : values) {
					if (value instanceof String[] stringArray) {
						merge(result, stringArray);
					}
					else if (value instanceof String string) {
						merge(result, string);
					}
				}
			}
			return result.isEmpty() ? Collections.emptySet() : result;
		}

private @Nullable ConditionOutcome[] getOutcomes(@Nullable String[] autoConfigurationClasses, int start,
				int end, AutoConfigurationMetadata autoConfigurationMetadata) {
			@Nullable ConditionOutcome[] outcomes = new ConditionOutcome[end - start];
			for (int i = start; i < end; i++) {
				String autoConfigurationClass = autoConfigurationClasses[i];
				if (autoConfigurationClass != null) {
					String candidates = autoConfigurationMetadata.get(autoConfigurationClass, "ConditionalOnClass");
					if (candidates != null) {
						outcomes[i - start] = getOutcome(candidates);
					}
				}
			}
			return outcomes;
		}

private ConditionOutcome isAnyWebApplication(ConditionContext context, boolean required) {
	ConditionMessage.Builder message = ConditionMessage.forCondition(ConditionalOnWebApplication.class,
			required ? "(required)" : "");
	ConditionOutcome servletOutcome = isServletWebApplication(context);
	if (servletOutcome.isMatch() && required) {
		return new ConditionOutcome(servletOutcome.isMatch(), message.because(servletOutcome.getMessage()));
	}
	ConditionOutcome reactiveOutcome = isReactiveWebApplication(context);
	if (reactiveOutcome.isMatch() && required) {
		return new ConditionOutcome(reactiveOutcome.isMatch(), message.because(reactiveOutcome.getMessage()));
	}
	return new ConditionOutcome(servletOutcome.isMatch() || reactiveOutcome.isMatch(),
			message.because(servletOutcome.getMessage()).append("and").append(reactiveOutcome.getMessage()));
}

private List<MethodMetadata> findBeanMethods(Source source, NoSuchBeanDefinitionException cause) {
	try {
		MetadataReader classMetadata = NoSuchBeanDefinitionFailureAnalyzer.this.metadataReaderFactory
			.getMetadataReader(source.getClassName());
		Set<MethodMetadata> candidates = classMetadata.getAnnotationMetadata()
			.getAnnotatedMethods(Bean.class.getName());
		List<MethodMetadata> result = new ArrayList<>();
		for (MethodMetadata candidate : candidates) {
			if (isMatch(candidate, source, cause)) {
				result.add(candidate);
			}
		}
		return Collections.unmodifiableList(result);
	}
	catch (Exception ex) {
		return Collections.emptyList();
	}
}

private void collectAnnotations(@Nullable Class<?> source, MultiValueMap<Class<?>, Annotation> annotations,
			HashSet<Class<?>> seen) {
		if (source != null && seen.add(source)) {
			for (Annotation annotation : source.getDeclaredAnnotations()) {
				if (!AnnotationUtils.isInJavaLangAnnotationPackage(annotation)) {
					if (ANNOTATION_NAMES.contains(annotation.annotationType().getName())) {
						annotations.add(source, annotation);
					}
					collectAnnotations(annotation.annotationType(), annotations, seen);
				}
			}
			collectAnnotations(source.getSuperclass(), annotations, seen);
		}
	}

private void registerNativeTypeConversion(Class<?> sourceType, Class<?> targetType) {
    if ( sourceType.isPrimitive() && targetType.isPrimitive() ) {
        register( sourceType, targetType, new PrimitiveToPrimitiveConversion( sourceType ) );
    }
    else if ( sourceType.isPrimitive() ) {
        register( sourceType, targetType, new PrimitiveToWrapperConversion( sourceType, targetType ) );
    }
    else if ( targetType.isPrimitive() ) {
        register( sourceType, targetType, inverse( new PrimitiveToWrapperConversion( targetType, sourceType ) ) );
    }
    else {
        register( sourceType, targetType, new WrapperToWrapperConversion( sourceType, targetType ) );
    }
}

protected void doOpen() throws Exception {
	Assert.notNull(this.resource, "The resource must not be null.");

	if (!this.resource.exists()) {
		if (this.strict) {
			throw new IllegalStateException("Input resource must exist (reader is in 'strict' mode)");
		}
		LOGGER.warn("Input resource does not exist " + this.resource.getDescription());
		return;
	}
	if (!this.resource.isReadable()) {
		if (this.strict) {
			throw new IllegalStateException("Input resource must be readable (reader is in 'strict' mode)");
		}
		LOGGER.warn("Input resource is not readable " + this.resource.getDescription());
		return;
	}
	this.jsonObjectReader.open(this.resource);
}

private void findSteps(Flow flow, Map<String, Step> map) {

	for (State state : flow.getStates()) {
		if (state instanceof ListableStepLocator locator) {
			for (String name : locator.getStepNames()) {
				map.put(name, locator.getStep(name));
			}
		}
		else if (state instanceof StepHolder stepHolder) {
			Step step = stepHolder.getStep();
			String name = step.getName();
			stepMap.put(name, step);
		}
		else if (state instanceof FlowHolder flowHolder) {
			for (Flow subflow : flowHolder.getFlows()) {
				findSteps(subflow, map);
			}
		}
	}

}

private void remove(Chunk<? extends T> chunk) {
	BulkOperations bulkOperations = initBulkOperations(chunk.getItems().get(0));
	@SuppressWarnings("DataFlowIssue")
	MongoConverter mongoConverter = this.template.getConverter();
	for (Object item : chunk) {
		Document document = new Document();
		mongoConverter.write(item, document);

		List<Criteria> criteriaList = primaryKeys.stream()
			.filter(document::containsKey)
			.map(key -> Criteria.where(key).is(document.get(key)))
			.collect(toList());
		if (!criteriaList.isEmpty()) {
			Query query = new Query();
			criteriaList.forEach(query::addCriteria);
			bulkOperations.remove(query);
		}
	}
	bulkOperations.execute();
}

public static <T> T instantiateClass(Class<T> clazz) throws BeanInstantiationException {
	Assert.notNull(clazz, "Class must not be null");
	if (clazz.isInterface()) {
		throw new BeanInstantiationException(clazz, "Specified class is an interface");
	}
	Constructor<T> ctor;
	try {
		ctor = clazz.getDeclaredConstructor();
	}
	catch (NoSuchMethodException ex) {
		ctor = findPrimaryConstructor(clazz);
		if (ctor == null) {
			throw new BeanInstantiationException(clazz, "No default constructor found", ex);
		}
	}
	catch (LinkageError err) {
		throw new BeanInstantiationException(clazz, "Unresolvable class definition", err);
	}
	return instantiateClass(ctor);
}

@Override
	public int compareTo(FlashMap other) {
		int thisUrlPath = (this.targetRequestPath != null ? 1 : 0);
		int otherUrlPath = (other.targetRequestPath != null ? 1 : 0);
		if (thisUrlPath != otherUrlPath) {
			return otherUrlPath - thisUrlPath;
		}
		else {
			return other.targetRequestParams.size() - this.targetRequestParams.size();
		}
	}

	@Override
	public boolean equals(@Nullable Object other) {
		return (this == other || (other instanceof FlashMap that &&
				super.equals(other) &&
				ObjectUtils.nullSafeEquals(this.targetRequestPath, that.targetRequestPath) &&
				this.targetRequestParams.equals(that.targetRequestParams)));
	}

	@Override
	public int hashCode() {
		int result = super.hashCode();
		result = 31 * result + ObjectUtils.nullSafeHashCode(this.targetRequestPath);
		result = 31 * result + this.targetRequestParams.hashCode();
		return result;
	}

@Override
	public boolean equals(@Nullable Object other) {
		if (this == other) {
			return true;
		}
		if (other == null || other.getClass() != getClass()) {
			return false;
		}
		HttpEntity<?> otherEntity = (HttpEntity<?>) other;
		return (ObjectUtils.nullSafeEquals(this.headers, otherEntity.headers) &&
				ObjectUtils.nullSafeEquals(this.body, otherEntity.body));
	}

	@Override
	public int hashCode() {
		return ObjectUtils.nullSafeHash(this.headers, this.body);
	}

	@Override
	public String toString() {
		StringBuilder builder = new StringBuilder("<");
		if (this.body != null) {
			builder.append(this.body);
			builder.append(',');
		}
		builder.append(this.headers);
		builder.append('>');
		return builder.toString();
	}

@Override
	public boolean equals(@Nullable Object other) {
		// Avoid TypeDescriptor initialization if not necessary
		return (this == other || (other instanceof TypedValue that &&
				ObjectUtils.nullSafeEquals(this.value, that.value) &&
				((this.typeDescriptor == null && that.typeDescriptor == null) ||
						ObjectUtils.nullSafeEquals(getTypeDescriptor(), that.getTypeDescriptor()))));
	}

	@Override
	public int hashCode() {
		return ObjectUtils.nullSafeHashCode(this.value);
	}

	@Override
	public String toString() {
		return "TypedValue: '" + this.value + "' of [" + getTypeDescriptor() + "]";
	}
